// Package imports:
import 'package:flutter_test/flutter_test.dart';
import 'package:hooks_riverpod/hooks_riverpod.dart';
import 'package:mockito/annotations.dart';
import 'package:mockito/mockito.dart';
import 'package:package_info_plus/package_info_plus.dart';

// Project imports:
import 'package:baseball_detector_flutter/controllers/version_controller.dart';
import 'package:baseball_detector_flutter/data/clients/static_file_client.dart';
import 'package:baseball_detector_flutter/data/clients/static_file_client_fake.dart';
import 'package:baseball_detector_flutter/data/models/failure/failure.dart';
import 'package:baseball_detector_flutter/data/models/version_info.dart';
import 'package:baseball_detector_flutter/data/models/version_state.dart';
import 'package:baseball_detector_flutter/data/result.dart';
import 'package:baseball_detector_flutter/providers/static_file_client_provider.dart';

@GenerateMocks([StaticFileClient])
void main() {
  TestWidgetsFlutterBinding.ensureInitialized();

  late ProviderContainer container;
  late FakeStaticFileClient mockStaticFileClient;

  setUp(() {
    // PackageInfo のモック設定（デフォルト値）
    PackageInfo.setMockInitialValues(
      appName: 'Baseball Detector',
      packageName: 'com.example.baseball_detector',
      version: '1.0.0',
      buildNumber: '10',
      buildSignature: '',
    );

    container = ProviderContainer(
      overrides: [
        staticFileClientProvider.overrideWithValue(FakeStaticFileClient()),
      ],
    );
  });

  tearDown(() {
    container.dispose();
  });

  group('VersionController', () {
    group('初期化', () {
      test('初期状態は Checking', () {
        final state = container.read(versionControllerProvider);
        expect(state, isA<Checking>());
      });
    });

    group('バージョン情報取得', () {
      test('最新バージョン使用中の場合 UpToDate を返す', () async {
        // Arrange
        final versionInfo = VersionInfo(
          android: VersionInfoPlatform(
            required: '1.0.0+10',
            latest: '1.0.0+10',
          ),
          ios: VersionInfoPlatform(
            required: '1.0.0+10',
            latest: '1.0.0+10',
          ),
        );
        when(mockStaticFileClient.fetchVersionInfo())
            .thenAnswer((_) async => Right(versionInfo));

        // Act
        final controller = container.read(versionControllerProvider.notifier);
        await controller.startObserving(true);

        // Assert
        final state = container.read(versionControllerProvider);
        expect(state, isA<UpToDate>());
        final upToDate = state as UpToDate;
        expect(upToDate.currentVersion, '1.0.0+10');
        expect(upToDate.latestVersion, '1.0.0+10');
      });

      test('任意アップデート可能な場合 UpdateAvailable を返す', () async {
        // Arrange
        final versionInfo = VersionInfo(
          android: VersionInfoPlatform(
            required: '1.0.0+10',
            latest: '1.1.0+15',
          ),
          ios: VersionInfoPlatform(
            required: '1.0.0+10',
            latest: '1.1.0+15',
          ),
        );
        when(mockStaticFileClient.fetchVersionInfo())
            .thenAnswer((_) async => Right(versionInfo));

        // Act
        final controller = container.read(versionControllerProvider.notifier);
        await controller.startObserving(true);

        // Assert
        final state = container.read(versionControllerProvider);
        expect(state, isA<UpdateAvailable>());
        final updateAvailable = state as UpdateAvailable;
        expect(updateAvailable.currentVersion, '1.0.0+10');
        expect(updateAvailable.latestVersion, '1.1.0+15');
      });

      test('強制アップデート必要な場合 UpdateRequired を返す', () async {
        // Arrange
        final versionInfo = VersionInfo(
          android: VersionInfoPlatform(
            required: '1.2.0+20',
            latest: '1.2.0+20',
          ),
          ios: VersionInfoPlatform(
            required: '1.2.0+20',
            latest: '1.2.0+20',
          ),
        );
        when(mockStaticFileClient.fetchVersionInfo())
            .thenAnswer((_) async => Right(versionInfo));

        // Act
        final controller = container.read(versionControllerProvider.notifier);
        await controller.startObserving(true);

        // Assert
        final state = container.read(versionControllerProvider);
        expect(state, isA<UpdateRequired>());
        final updateRequired = state as UpdateRequired;
        expect(updateRequired.currentVersion, '1.0.0+10');
        expect(updateRequired.requiredVersion, '1.2.0+20');
        expect(updateRequired.latestVersion, '1.2.0+20');
      });

      test('API エラーの場合 VersionError を返す', () async {
        // Arrange
        final failure = Failure.undefined(
          code: 'TEST_ERROR',
        );
        when(mockStaticFileClient.fetchVersionInfo())
            .thenAnswer((_) async => Left(failure));

        // Act
        final controller = container.read(versionControllerProvider.notifier);
        await controller.startObserving(true);

        // Assert
        final state = container.read(versionControllerProvider);
        expect(state, isA<VersionError>());
        final versionError = state as VersionError;
        expect(versionError.message, 'Network error');
      });

      test('無効なバージョン形式の場合 VersionError を返す', () async {
        // Arrange
        final versionInfo = VersionInfo(
          android: VersionInfoPlatform(
            required: 'invalid-version',
            latest: '1.1.0+15',
          ),
          ios: VersionInfoPlatform(
            required: 'invalid-version',
            latest: '1.1.0+15',
          ),
        );
        when(mockStaticFileClient.fetchVersionInfo())
            .thenAnswer((_) async => Right(versionInfo));

        // Act
        final controller = container.read(versionControllerProvider.notifier);
        await controller.startObserving(true);

        // Assert
        final state = container.read(versionControllerProvider);
        expect(state, isA<UpdateAvailable>());
      });
    });

    group('タイマー管理', () {
      test('強制アップデート状態の場合はタイマーを設定しない', () async {
        // Arrange
        final versionInfo = VersionInfo(
          android: VersionInfoPlatform(
            required: '1.2.0+20',
            latest: '1.2.0+20',
          ),
          ios: VersionInfoPlatform(
            required: '1.2.0+20',
            latest: '1.2.0+20',
          ),
        );
        when(mockStaticFileClient.fetchVersionInfo())
            .thenAnswer((_) async => Right(versionInfo));

        // Act
        final controller = container.read(versionControllerProvider.notifier);
        await controller.startObserving(true);

        // UpdateRequired 状態でタイマー再設定を試みる
        await controller.startObserving(false);

        // Assert
        // タイマーが設定されていないことを間接的に確認
        // (直接アクセスできないため、動作で確認)
        verify(mockStaticFileClient.fetchVersionInfo()).called(1);
      });

      test('通常状態の場合はタイマーを設定する', () async {
        // Arrange
        final versionInfo = VersionInfo(
          android: VersionInfoPlatform(
            required: '1.0.0+10',
            latest: '1.0.0+10',
          ),
          ios: VersionInfoPlatform(
            required: '1.0.0+10',
            latest: '1.0.0+10',
          ),
        );
        when(mockStaticFileClient.fetchVersionInfo())
            .thenAnswer((_) async => Right(versionInfo));

        // Act
        final controller = container.read(versionControllerProvider.notifier);
        await controller.startObserving(false);

        // Assert
        // タイマーが設定されていることを確認
        verify(mockStaticFileClient.fetchVersionInfo()).called(1);
      });

      test('stopObserving でタイマーを停止する', () async {
        // Arrange
        final versionInfo = VersionInfo(
          android: VersionInfoPlatform(
            required: '1.0.0+10',
            latest: '1.0.0+10',
          ),
          ios: VersionInfoPlatform(
            required: '1.0.0+10',
            latest: '1.0.0+10',
          ),
        );
        when(mockStaticFileClient.fetchVersionInfo())
            .thenAnswer((_) async => Right(versionInfo));

        // Act
        final controller = container.read(versionControllerProvider.notifier);
        await controller.startObserving(false);
        controller.stopObserving();

        // Assert
        // stopObserving が正常に呼び出されることを確認
        expect(() => controller.stopObserving(), returnsNormally);
      });
    });

    group('例外処理', () {
      test('fetchVersionInfo で例外が発生した場合 VersionError を返す', () async {
        // Arrange
        when(mockStaticFileClient.fetchVersionInfo())
            .thenThrow(Exception('Network timeout'));

        // Act
        final controller = container.read(versionControllerProvider.notifier);
        await controller.startObserving(true);

        // Assert
        final state = container.read(versionControllerProvider);
        expect(state, isA<VersionError>());
        final versionError = state as VersionError;
        expect(versionError.message, contains('Exception: Network timeout'));
      });

      test('現在のバージョンが解析できない場合 VersionError を返す', () async {
        // Arrange
        PackageInfo.setMockInitialValues(
          appName: 'Baseball Detector',
          packageName: 'com.example.baseball_detector',
          version: 'invalid',
          buildNumber: 'invalid',
          buildSignature: '',
        );

        final versionInfo = VersionInfo(
          android: VersionInfoPlatform(
            required: '1.0.0+10',
            latest: '1.1.0+15',
          ),
          ios: VersionInfoPlatform(
            required: '1.0.0+10',
            latest: '1.1.0+15',
          ),
        );
        when(mockStaticFileClient.fetchVersionInfo())
            .thenAnswer((_) async => Right(versionInfo));

        // Act
        final controller = container.read(versionControllerProvider.notifier);
        await controller.startObserving(true);

        // Assert
        final state = container.read(versionControllerProvider);
        expect(state, isA<VersionError>());
        final versionError = state as VersionError;
        expect(versionError.message, 'Failed to parse current version');
        expect(versionError.currentVersion, 'invalid+invalid');
      });
    });

    group('バージョン比較', () {
      test('required バージョンが null の場合、強制アップデートにならない', () async {
        // Arrange
        final versionInfo = VersionInfo(
          android: VersionInfoPlatform(
            required: null,
            latest: '1.1.0+15',
          ),
          ios: VersionInfoPlatform(
            required: null,
            latest: '1.1.0+15',
          ),
        );
        when(mockStaticFileClient.fetchVersionInfo())
            .thenAnswer((_) async => Right(versionInfo));

        // Act
        final controller = container.read(versionControllerProvider.notifier);
        await controller.startObserving(true);

        // Assert
        final state = container.read(versionControllerProvider);
        expect(state, isA<UpdateAvailable>());
      });

      test('latest バージョンが null の場合、任意アップデートにならない', () async {
        // Arrange
        final versionInfo = VersionInfo(
          android: VersionInfoPlatform(
            required: '1.0.0+10',
            latest: null,
          ),
          ios: VersionInfoPlatform(
            required: '1.0.0+10',
            latest: null,
          ),
        );
        when(mockStaticFileClient.fetchVersionInfo())
            .thenAnswer((_) async => Right(versionInfo));

        // Act
        final controller = container.read(versionControllerProvider.notifier);
        await controller.startObserving(true);

        // Assert
        final state = container.read(versionControllerProvider);
        expect(state, isA<UpToDate>());
        final upToDate = state as UpToDate;
        expect(upToDate.latestVersion, '1.0.0+10'); // currentVersion を使用
      });

      test('required と latest の両方が null の場合', () async {
        // Arrange
        final versionInfo = VersionInfo(
          android: VersionInfoPlatform(
            required: null,
            latest: null,
          ),
          ios: VersionInfoPlatform(
            required: null,
            latest: null,
          ),
        );
        when(mockStaticFileClient.fetchVersionInfo())
            .thenAnswer((_) async => Right(versionInfo));

        // Act
        final controller = container.read(versionControllerProvider.notifier);
        await controller.startObserving(true);

        // Assert
        final state = container.read(versionControllerProvider);
        expect(state, isA<UpToDate>());
        final upToDate = state as UpToDate;
        expect(upToDate.currentVersion, '1.0.0+10');
        expect(upToDate.latestVersion, '1.0.0+10');
      });
    });
  });
}

